 1	import type { ComponentProps, FC } from 'react';
 2	import { Base64 } from 'js-base64';
 3	import Loading from 'src/overview/components/Loading';
 4	
 5	import { CodeEditor as SDKCodeEditor } from '@openshift-console/dynamic-plugin-sdk';
 6	import { CodeEditor as PFCodeEditor, Language as PFLanguage } from '@patternfly/react-code-editor';
 7	import useOpenshiftClusterVersion from '@utils/hooks/useOpenshiftClusterVersion/useOpenshiftClusterVersion';
 8	
 9	import { OCP_VERSION_4_18 } from './utils/constants';
10	import { isVersionGte } from './utils/utils';
11	
12	type VersionedCodeEditorProps = Pick<
13	  ComponentProps<typeof PFCodeEditor>,
14	  'isReadOnly' | 'isDarkTheme'
15	> & {
16	  value: string | undefined;
17	  onChange: (encodedValue: string) => void;
18	  minHeight?: string;
19	};
20	
21	// VersionedCodeEditor component that uses the appropriate CodeEditor based on OCP version
22	// https://issues.redhat.com/browse/MTV-2918
23	const VersionedCodeEditor: FC<VersionedCodeEditorProps> = ({
24	  isDarkTheme,
25	  isReadOnly,
26	  minHeight = '20rem',
27	  onChange,
28	  value,
29	}) => {
30	  const [ocpVersion, loaded] = useOpenshiftClusterVersion();
31	
32	  const decodedValue = Base64.decode(value ?? '');
33	
34	  if (!loaded) {
35	    return <Loading />;
36	  }
37	
38	  // Checking it's OCP version 4.18 or greater to decide which CodeEditor to use
39	  // on OCP 4.17 PF code editor is not used, And
40	  // on OCP 4.19 SDK code editor is having a bug where it doesn't show the code
41	  if (isVersionGte(ocpVersion, OCP_VERSION_4_18)) {
42	    return (
43	      <PFCodeEditor
44	        isDarkTheme={isDarkTheme}
45	        language={PFLanguage.yaml}
46	        code={decodedValue}
47	        onChange={(val) => {
48	          onChange(Base64.encode(String(val)));
49	        }}
50	        height={minHeight}
51	        isMinimapVisible={false}
52	        isReadOnly={isReadOnly}
53	      />
54	    );
55	  }
56	
57	  return (
58	    <SDKCodeEditor
59	      language="yaml"
60	      value={decodedValue}
61	      onChange={(val) => {
62	        onChange(Base64.encode(String(val)));
63	      }}
64	      minHeight={minHeight}
65	      showMiniMap={false}
66	    />
67	  );
68	};
69	
70	export default VersionedCodeEditor;

